//! Protocol-mode exec proxy loops for byte-preserving stdio forwarding.
//!
//! Unlike interactive attached sessions, protocol mode must behave as a raw
//! stdio bridge. That means no terminal resize handling, no local echo, and no
//! host-generated bytes on stdout.
//!
//! ## Stdout Purity Contract
//!
//! The protocol proxy must never write bytes to host stdout that did not
//! originate from container stdout or console output. This means:
//!
//! - No banners, progress indicators, or status messages
//! - No diagnostic output or error messages (these go to stderr)
//! - No echoed stdin bytes (explicitly suppressed via `LogOutput::StdIn` routing)
//! - No framing, escaping, or encoding of the byte stream
//!
//! This contract is enforced by construction: `run_protocol_session_with_io_async`
//! accepts injected host-IO handles and only writes to `host_stdout` in
//! `handle_log_output_chunk` for `LogOutput::StdOut` and `LogOutput::Console`
//! messages from the container. All other code paths route to stderr or return
//! errors without touching stdout.

use std::io;
use std::pin::Pin;
use std::task::{Context, Poll};
use std::time::Duration;

use bollard::container::LogOutput;
use bollard::errors::Error as BollardError;
use futures_util::{Stream, StreamExt};
use tokio::io::{AsyncRead, AsyncWrite, AsyncWriteExt};
use tokio::task::JoinHandle;
use tokio::time::timeout;

#[path = "acp_helpers.rs"]
mod acp_helpers;

use super::helpers::spawn_stdin_forwarding_task;
use super::host_io::stdin_forwarding_disabled_for_tests;
use super::{ExecRequest, exec_failed};
use crate::error::PodbotError;

/// Host-side stdio handles used by the protocol byte proxy.
pub(super) struct ProtocolProxyIo<HostStdin, HostStdout, HostStderr> {
    /// Host stdin reader supplied to the forwarding task.
    stdin: HostStdin,
    /// Host stdout writer used for container stdout and console output.
    stdout: HostStdout,
    /// Host stderr writer used for container stderr and error diagnostics.
    stderr: HostStderr,
    /// Per-session configuration knobs applied to this proxy run.
    options: ProtocolSessionOptions,
}

/// Allow a short grace period for EOF- and flush-driven completion paths to
/// finish before treating stdin forwarding as stalled. `50ms` matches typical
/// local pipe and socket flush timings in this code path without adding a
/// noticeable shutdown delay; if future benchmarks or transport changes show
/// different behaviour, adjust `STDIN_SETTLE_TIMEOUT` and extend the proxy
/// tests that exercise EOF and non-EOF stdin shutdown cases.
const STDIN_SETTLE_TIMEOUT: Duration = Duration::from_millis(50);

/// Maximum bytes buffered between host stdin reads and container input writes.
/// This bounds memory consumption per read cycle and provides backpressure by
/// limiting how many bytes can be in flight. A 64 KiB buffer aligns with common
/// protocol message sizes and typical OS pipe buffer defaults, keeping latency
/// low while preventing unbounded accumulation during high-throughput scenarios.
const STDIN_BUFFER_CAPACITY: usize = 65_536;

/// Per-session configuration knobs for protocol-mode exec proxy loops.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
pub(super) struct ProtocolSessionOptions {
    /// When `true`, host stdin is replaced by a held-open no-op reader so that
    /// the process's inherited stdin is never forwarded to the container.
    disable_stdin_forwarding: bool,
    /// When `true`, the first ACP `initialize` frame is rewritten to remove
    /// `terminal` and `fs` capabilities before being forwarded to the container.
    rewrite_acp_initialize: bool,
}

impl ProtocolSessionOptions {
    /// Create default protocol-session options with production behaviour.
    pub(super) const fn new() -> Self {
        Self {
            disable_stdin_forwarding: false,
            rewrite_acp_initialize: false,
        }
    }

    /// Disable or enable protocol stdin forwarding for this session.
    pub(super) const fn with_stdin_forwarding_disabled(mut self, disable: bool) -> Self {
        self.disable_stdin_forwarding = disable;
        self
    }

    /// Enable or disable Agentic Control Protocol (ACP) initialisation rewriting for this protocol session.
    pub(super) const fn with_acp_initialize_rewrite_enabled(mut self, enable: bool) -> Self {
        self.rewrite_acp_initialize = enable;
        self
    }
}

/// An `AsyncRead` adapter that stays open indefinitely without producing
/// bytes, used to suppress inherited process stdin while the forwarding task
/// remains alive.
struct HeldOpenStdin {
    /// The read half of the in-memory duplex pipe; never yields bytes.
    reader: tokio::io::DuplexStream,
    /// Keeps the write half alive so `reader` never sees EOF.
    _writer_guard: tokio::io::DuplexStream,
}

impl tokio::io::AsyncRead for HeldOpenStdin {
    /// Delegates to the inner duplex reader, which blocks indefinitely without producing bytes.
    fn poll_read(
        mut self: Pin<&mut Self>,
        cx: &mut Context<'_>,
        buf: &mut tokio::io::ReadBuf<'_>,
    ) -> Poll<io::Result<()>> {
        Pin::new(&mut self.reader).poll_read(cx, buf)
    }
}

impl<HostStdin, HostStdout, HostStderr> ProtocolProxyIo<HostStdin, HostStdout, HostStderr> {
    /// Create a host-IO bundle for a protocol proxy session.
    pub(super) const fn new(
        host_stdin: HostStdin,
        host_stdout: HostStdout,
        host_stderr: HostStderr,
    ) -> Self {
        Self {
            stdin: host_stdin,
            stdout: host_stdout,
            stderr: host_stderr,
            options: ProtocolSessionOptions::new(),
        }
    }

    /// Attach session options to this host-IO bundle.
    pub(super) const fn with_options(mut self, options: ProtocolSessionOptions) -> Self {
        self.options = options;
        self
    }
}

/// Run a protocol exec session using real host stdio and the given session
/// options.
pub(super) async fn run_protocol_session_async_with_options(
    request: &ExecRequest,
    output: Pin<Box<dyn Stream<Item = Result<LogOutput, BollardError>> + Send>>,
    input: Pin<Box<dyn AsyncWrite + Send>>,
    options: ProtocolSessionOptions,
) -> Result<(), PodbotError> {
    let stdio = ProtocolProxyIo::new(
        protocol_host_stdin(options),
        tokio::io::stdout(),
        tokio::io::stderr(),
    )
    .with_options(options);
    run_protocol_session_with_io_async(request, output, input, stdio).await
}

/// Return the appropriate stdin reader for a protocol session. Yields a
/// held-open no-op reader when stdin forwarding is disabled.
fn protocol_host_stdin(options: ProtocolSessionOptions) -> Pin<Box<dyn AsyncRead + Send>> {
    if options.disable_stdin_forwarding || stdin_forwarding_disabled_for_tests() {
        let (writer_guard, reader) = tokio::io::duplex(1);
        Box::pin(HeldOpenStdin {
            reader,
            _writer_guard: writer_guard,
        })
    } else {
        Box::pin(tokio::io::stdin())
    }
}

/// Run a protocol exec session using caller-supplied host IO handles.
pub(super) async fn run_protocol_session_with_io_async<HostStdin, HostStdout, HostStderr>(
    request: &ExecRequest,
    mut output: Pin<Box<dyn Stream<Item = Result<LogOutput, BollardError>> + Send>>,
    input: Pin<Box<dyn AsyncWrite + Send>>,
    stdio: ProtocolProxyIo<HostStdin, HostStdout, HostStderr>,
) -> Result<(), PodbotError>
where
    HostStdin: AsyncRead + Send + Unpin + 'static,
    HostStdout: AsyncWrite + Send + Unpin,
    HostStderr: AsyncWrite + Send + Unpin,
{
    let ProtocolProxyIo {
        stdin: host_stdin,
        stdout: mut host_stdout,
        stderr: mut host_stderr,
        options,
    } = stdio;
    let rewrite_acp_initialize = options.rewrite_acp_initialize;
    let stdin_task =
        spawn_stdin_forwarding_task(host_stdin, input, move |stdin_reader, exec_input| {
            forward_host_stdin_to_exec_async(stdin_reader, exec_input, rewrite_acp_initialize)
        });
    let output_result = run_output_loop_async(
        request.container_id(),
        &mut output,
        &mut host_stdout,
        &mut host_stderr,
    )
    .await;
    let stdin_result =
        settle_stdin_forwarding_task(request.container_id(), stdin_task, options).await;
    output_result?;
    stdin_result
}

/// Wait for the stdin forwarding task to complete within a short grace
/// period.
async fn settle_stdin_forwarding_task(
    container_id: &str,
    mut stdin_task: JoinHandle<io::Result<()>>,
    options: ProtocolSessionOptions,
) -> Result<(), PodbotError> {
    let Ok(join_result) = timeout(STDIN_SETTLE_TIMEOUT, &mut stdin_task).await else {
        // The container output path has already completed, so stdin can be
        // cancelled instead of waiting indefinitely on a live host reader. A
        // timeout here still indicates that stdin forwarding did not complete
        // cleanly before shutdown, so protocol mode must surface that failure
        // instead of reporting success with potentially truncated input.
        abort_stdin_forwarding_task(stdin_task);
        if options.disable_stdin_forwarding || stdin_forwarding_disabled_for_tests() {
            return Ok(());
        }
        return Err(exec_failed(
            container_id,
            "stdin forwarding did not complete before protocol session shutdown",
        ));
    };

    classify_stdin_forwarding_task_result(container_id, join_result)
}

/// Map a join result from the stdin forwarding task to a `PodbotError`.
fn classify_stdin_forwarding_task_result(
    container_id: &str,
    join_result: Result<io::Result<()>, tokio::task::JoinError>,
) -> Result<(), PodbotError> {
    match join_result {
        Ok(Ok(())) => Ok(()),
        Ok(Err(error)) => Err(exec_failed(
            container_id,
            format!("failed forwarding stdin to exec input: {error}"),
        )),
        Err(error) if error.is_cancelled() => Ok(()),
        Err(error) => Err(exec_failed(
            container_id,
            format!("stdin forwarding task failed: {error}"),
        )),
    }
}

/// Abort and drop the stdin forwarding task without awaiting it.
fn abort_stdin_forwarding_task(stdin_task: JoinHandle<io::Result<()>>) {
    if !stdin_task.is_finished() {
        stdin_task.abort();
        // Avoid awaiting the aborted task here because host stdin may be
        // blocked in a non-cancellable read. Dropping the handle mirrors the
        // attached-session shutdown path and keeps teardown bounded.
        drop(stdin_task);
    }
}

/// Copy host stdin to the container exec input, optionally rewriting the
/// first ACP `initialize` frame before the raw copy begins.
async fn forward_host_stdin_to_exec_async<HostStdin>(
    host_stdin: HostStdin,
    mut input: Pin<Box<dyn AsyncWrite + Send>>,
    rewrite_acp_initialize: bool,
) -> io::Result<()>
where
    HostStdin: AsyncRead + Unpin,
{
    let mut buffered_stdin = tokio::io::BufReader::with_capacity(STDIN_BUFFER_CAPACITY, host_stdin);

    if rewrite_acp_initialize {
        acp_helpers::forward_initial_acp_frame_async(&mut buffered_stdin, &mut input).await?;
    }
    tokio::io::copy(&mut buffered_stdin, &mut input).await?;

    input.flush().await?;
    input.shutdown().await
}

